## Deliverables

### 1. Build Info Generation
At build time, generate a file with version info:

```typescript
// scripts/generate-build-info.ts
import { execSync } from "child_process";
import { writeFileSync } from "fs";

const buildInfo = {
  version: process.env.npm_package_version || "0.0.0",
  commit: execSync("git rev-parse --short HEAD").toString().trim(),
  branch: execSync("git rev-parse --abbrev-ref HEAD").toString().trim(),
  buildTime: new Date().toISOString(),
};

writeFileSync(
  "apps/gateway/src/build-info.ts",
  `// Auto-generated at build time - DO NOT EDIT
export const BUILD_INFO = ${JSON.stringify(buildInfo, null, 2)} as const;
`
);
```

Add to package.json:
```json
{
  "scripts": {
    "prebuild": "bun scripts/generate-build-info.ts",
    "build": "..."
  }
}
```

### 2. Uptime Tracking
```typescript
// apps/gateway/src/utils/uptime.ts

const startupTime = Date.now();

/**
 * Get server uptime in seconds.
 */
export function getUptime(): number {
  return Math.floor((Date.now() - startupTime) / 1000);
}

/**
 * Get startup timestamp.
 */
export function getStartupTime(): Date {
  return new Date(startupTime);
}
```

### 3. Capabilities Definition
```typescript
// apps/gateway/src/config/capabilities.ts

export interface Capabilities {
  websocket: boolean;
  checkpoints: boolean;
  fleet: boolean;
  mail: boolean;
  dcg: boolean;
}

export function getCapabilities(): Capabilities {
  return {
    websocket: true,  // Always available
    checkpoints: true,  // Always available
    fleet: process.env.ENABLE_FLEET === "true",
    mail: !!process.env.AGENTMAIL_URL,
    dcg: !!process.env.DCG_PATH,
  };
}
```

### 4. Enhanced Health Route
```typescript
// apps/gateway/src/routes/health.ts

import { BUILD_INFO } from "../build-info";
import { getUptime, getStartupTime } from "../utils/uptime";
import { getCapabilities } from "../config/capabilities";

health.get("/", (c) => {
  return c.json({
    status: "healthy",
    version: BUILD_INFO.version,
    commit: BUILD_INFO.commit,
    uptime: getUptime(),
    startedAt: getStartupTime().toISOString(),
    environment: process.env.NODE_ENV || "development",
    timestamp: new Date().toISOString(),
    capabilities: getCapabilities(),
    correlationId: getCorrelationId(),
  });
});
```

### 5. Detailed Readiness Check (Optional Enhancement)
```typescript
health.get("/ready", async (c) => {
  const checks = {
    database: await checkDatabase(),
    drivers: checkDrivers(),
    mail: await checkMailService(),
    dcg: await checkDCG(),
  };

  const allPass = Object.values(checks).every((c) => c.status === "pass");
  const anyFail = Object.values(checks).some((c) => c.status === "fail");

  return c.json({
    status: anyFail ? "unhealthy" : allPass ? "ready" : "degraded",
    version: BUILD_INFO.version,
    uptime: getUptime(),
    checks,
    timestamp: new Date().toISOString(),
  }, anyFail ? 503 : 200);
});
```

